"use client";

import {
  ArrowDownCircle,
  ArrowUpCircle,
  Pencil,
  Plus,
  ShoppingCart,
  Trash2
} from "lucide-react";
import { useMemo, useState } from "react";
import { Button } from "@/components/ui/button";
import { DataTable } from "@/components/ui/data-table";
import { Input } from "@/components/ui/input";
import { SectionHeading } from "@/components/ui/section-heading";
import { Select } from "@/components/ui/select";
import { SmartNumberInput } from "@/components/ui/smart-number-input";
import { useAppData } from "@/contexts/app-data-context";
import { financeTotals } from "@/lib/metrics";
import type { ExpenseCategory, FinanceEntry, FinanceType } from "@/lib/types";
import { formatCurrency, todayISO, startOfMonthISO } from "@/lib/utils";

const typeOptions: FinanceType[] = ["Entrada", "Saída"];
const categoryOptions: Array<ExpenseCategory | "Vendas" | "Sinal" | "Outros"> = [
  "Vendas",
  "Sinal",
  "Ingredientes",
  "Embalagens",
  "Entrega",
  "Marketing",
  "Equipamentos",
  "Transporte",
  "Outros"
];

const emptyForm = {
  type: "Saída" as FinanceType,
  category: "Ingredientes" as ExpenseCategory | "Vendas" | "Sinal" | "Outros",
  description: "",
  amount: 0,
  date: todayISO()
};

const emptySaleForm = {
  productId: "",
  quantity: 1,
  unitPrice: 0,
  discount: 0,
  date: todayISO(),
  description: ""
};

export function FinanceScreen() {
  const { state, addFinance, updateFinance, deleteFinance } = useAppData();
  const [editing, setEditing] = useState<FinanceEntry | null>(null);
  const [form, setForm] = useState(emptyForm);
  const [saleForm, setSaleForm] = useState(() => {
    const firstProduct = state.products[0];
    return {
      ...emptySaleForm,
      productId: firstProduct?.id ?? "",
      unitPrice: firstProduct?.price ?? 0
    };
  });

  const range = useMemo(
    () => financeTotals(state.financeEntries, startOfMonthISO(), todayISO()),
    [state.financeEntries]
  );

  const reset = () => {
    setEditing(null);
    setForm(emptyForm);
  };

  const resetSale = () => {
    const firstProduct = state.products[0];
    setSaleForm({
      ...emptySaleForm,
      productId: firstProduct?.id ?? "",
      unitPrice: firstProduct?.price ?? 0
    });
  };

  const saleTotal = Math.max(saleForm.quantity * saleForm.unitPrice - saleForm.discount, 0);

  const submit = (event: React.FormEvent) => {
    event.preventDefault();

    if (editing) {
      updateFinance({ ...editing, ...form });
    } else {
      addFinance(form);
    }

    reset();
  };

  const submitQuickSale = (event: React.FormEvent) => {
    event.preventDefault();

    if (!saleForm.productId || saleTotal <= 0) return;

    const product = state.products.find((item) => item.id === saleForm.productId);

    addFinance({
      type: "Entrada",
      category: "Vendas",
      description:
        saleForm.description.trim() ||
        `Venda rápida • ${product?.name ?? "Produto"} x${saleForm.quantity}`,
      amount: saleTotal,
      date: saleForm.date
    });

    resetSale();
  };

  const startEdit = (entry: FinanceEntry) => {
    setEditing(entry);
    setForm({
      type: entry.type,
      category: entry.category,
      description: entry.description,
      amount: entry.amount,
      date: entry.date
    });
  };

  const handleSaleProductChange = (productId: string) => {
    const product = state.products.find((item) => item.id === productId);

    setSaleForm((current) => ({
      ...current,
      productId,
      unitPrice: product?.price ?? 0,
      description: current.description
    }));
  };

  const rows = state.financeEntries
    .slice()
    .sort((a, b) => b.date.localeCompare(a.date))
    .map((entry) => [
      entry.date,
      <span
        key={`${entry.id}-type`}
        className={`rounded-full px-3 py-1 text-xs font-semibold ${
          entry.type === "Entrada"
            ? "bg-emerald-50 text-emerald-700"
            : "bg-red-50 text-red-700"
        }`}
      >
        {entry.type}
      </span>,
      entry.category,
      entry.description,
      formatCurrency(entry.amount),
      <div key={`${entry.id}-actions`} className="flex gap-2">
        <Button variant="ghost" className="px-3 py-2" onClick={() => startEdit(entry)}>
          <Pencil className="h-4 w-4" />
        </Button>
        <Button variant="danger" className="px-3 py-2" onClick={() => deleteFinance(entry.id)}>
          <Trash2 className="h-4 w-4" />
        </Button>
      </div>
    ]);

  return (
    <div className="space-y-6">
      <SectionHeading
        eyebrow="Financeiro"
        title="Caixa e vendas"
        description="Registre entradas, saídas e também vendas rápidas do dia a dia."
      />

      <div className="grid gap-4 md:grid-cols-3">
        <div className="surface rounded-[28px] p-5">
          <div className="mb-3 inline-flex rounded-2xl bg-emerald-50 p-3 text-emerald-700">
            <ArrowUpCircle className="h-5 w-5" />
          </div>
          <p className="text-sm text-neutral-500">Entradas do mês</p>
          <p className="mt-2 text-2xl font-bold">{formatCurrency(range.entriesTotal)}</p>
        </div>

        <div className="surface rounded-[28px] p-5">
          <div className="mb-3 inline-flex rounded-2xl bg-red-50 p-3 text-red-700">
            <ArrowDownCircle className="h-5 w-5" />
          </div>
          <p className="text-sm text-neutral-500">Saídas do mês</p>
          <p className="mt-2 text-2xl font-bold">{formatCurrency(range.expensesTotal)}</p>
        </div>

        <div className="surface rounded-[28px] p-5">
          <div className="mb-3 inline-flex rounded-2xl bg-pink-50 p-3 text-pink-700">
            <ShoppingCart className="h-5 w-5" />
          </div>
          <p className="text-sm text-neutral-500">Saldo do mês</p>
          <p className="mt-2 text-2xl font-bold">{formatCurrency(range.net)}</p>
        </div>
      </div>

      <div className="grid gap-6 xl:grid-cols-2">
        <form className="surface rounded-[28px] p-5 space-y-4" onSubmit={submitQuickSale}>
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-pink-600">Ação rápida</p>
              <h3 className="text-xl font-bold">Registrar venda</h3>
            </div>
            <Button type="button" variant="secondary" onClick={resetSale}>
              Limpar
            </Button>
          </div>

          <div>
            <label className="mb-2 block text-sm font-semibold">Produto</label>
            <Select
              value={saleForm.productId}
              onChange={(e) => handleSaleProductChange(e.target.value)}
              required
            >
              <option value="">Selecione um produto</option>
              {state.products.map((product) => (
                <option key={product.id} value={product.id}>
                  {product.name}
                </option>
              ))}
            </Select>
          </div>

          <div className="grid gap-4 md:grid-cols-3">
            <div>
              <label className="mb-2 block text-sm font-semibold">Quantidade</label>
              <SmartNumberInput
                value={saleForm.quantity}
                onValueChange={(value) =>
                  setSaleForm((current) => ({
                    ...current,
                    quantity: Math.max(1, Math.trunc(value || 0))
                  }))
                }
                decimals={0}
                min={1}
                placeholder="1"
              />
            </div>

            <div>
              <label className="mb-2 block text-sm font-semibold">Valor unitário</label>
              <SmartNumberInput
                value={saleForm.unitPrice}
                onValueChange={(value) =>
                  setSaleForm((current) => ({ ...current, unitPrice: value }))
                }
                placeholder="0,00"
              />
            </div>

            <div>
              <label className="mb-2 block text-sm font-semibold">Desconto</label>
              <SmartNumberInput
                value={saleForm.discount}
                onValueChange={(value) =>
                  setSaleForm((current) => ({ ...current, discount: value }))
                }
                placeholder="0,00"
              />
            </div>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            <div>
              <label className="mb-2 block text-sm font-semibold">Data</label>
              <Input
                type="date"
                value={saleForm.date}
                onChange={(e) => setSaleForm((current) => ({ ...current, date: e.target.value }))}
                required
              />
            </div>

            <div>
              <label className="mb-2 block text-sm font-semibold">Descrição</label>
              <Input
                value={saleForm.description}
                onChange={(e) =>
                  setSaleForm((current) => ({ ...current, description: e.target.value }))
                }
                placeholder="Ex.: Venda no balcão"
              />
            </div>
          </div>

          <div className="rounded-3xl border border-pink-100 bg-pink-50/60 p-4">
            <p className="text-sm text-neutral-500">Total da venda</p>
            <p className="mt-2 text-2xl font-bold">{formatCurrency(saleTotal)}</p>
          </div>

          <Button type="submit" className="w-full">
            Registrar venda
          </Button>
        </form>

        <form className="surface rounded-[28px] p-5 space-y-4" onSubmit={submit}>
          <div className="flex items-center justify-between">
            <h3 className="text-xl font-bold">
              {editing ? "Editar lançamento" : "Novo lançamento manual"}
            </h3>
            <Button type="button" variant="secondary" className="gap-2" onClick={reset}>
              <Plus className="h-4 w-4" />
              Limpar
            </Button>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            <div>
              <label className="mb-2 block text-sm font-semibold">Tipo</label>
              <Select
                value={form.type}
                onChange={(e) =>
                  setForm((current) => ({ ...current, type: e.target.value as FinanceType }))
                }
              >
                {typeOptions.map((option) => (
                  <option key={option}>{option}</option>
                ))}
              </Select>
            </div>

            <div>
              <label className="mb-2 block text-sm font-semibold">Categoria</label>
              <Select
                value={form.category}
                onChange={(e) =>
                  setForm((current) => ({
                    ...current,
                    category: e.target.value as ExpenseCategory | "Vendas" | "Sinal" | "Outros"
                  }))
                }
              >
                {categoryOptions.map((option) => (
                  <option key={option}>{option}</option>
                ))}
              </Select>
            </div>
          </div>

          <div>
            <label className="mb-2 block text-sm font-semibold">Descrição</label>
            <Input
              value={form.description}
              onChange={(e) => setForm((current) => ({ ...current, description: e.target.value }))}
              placeholder="Ex.: compra de caixa, sinal recebido, ingrediente..."
              required
            />
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            <div>
              <label className="mb-2 block text-sm font-semibold">Valor</label>
              <SmartNumberInput
                value={form.amount}
                onValueChange={(value) => setForm((current) => ({ ...current, amount: value }))}
                placeholder="0,00"
                required
              />
            </div>

            <div>
              <label className="mb-2 block text-sm font-semibold">Data</label>
              <Input
                type="date"
                value={form.date}
                onChange={(e) => setForm((current) => ({ ...current, date: e.target.value }))}
                required
              />
            </div>
          </div>

          <Button type="submit" className="w-full">
            {editing ? "Salvar lançamento" : "Cadastrar lançamento"}
          </Button>
        </form>
      </div>

      <DataTable
        headers={["Data", "Tipo", "Categoria", "Descrição", "Valor", "Ações"]}
        rows={rows}
      />
    </div>
  );
}